section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/finops-governance.json",
  "title": "FinOps OPERATE Phase \u2014 Governance and Cost Gates",
  "type": "object",
  "required": [
    "budgets",
    "ci_cost_gate",
    "auto_stop_policy",
    "policies",
    "variance_cap_pct",
    "owner",
    "last_reviewed"
  ],
  "properties": {
    "budgets": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": [
          "scope",
          "monthly_usd",
          "owner",
          "alerts"
        ]
      }
    },
    "ci_cost_gate": {
      "type": "object",
      "required": [
        "tool",
        "max_delta_usd_per_pr"
      ]
    },
    "auto_stop_policy": {
      "type": "object",
      "required": [
        "environments",
        "idle_window_hours"
      ]
    },
    "policies": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": [
          "name",
          "engine",
          "config_ref"
        ]
      }
    },
    "variance_cap_pct": {
      "type": "number"
    },
    "owner": {
      "type": "string"
    },
    "last_reviewed": {
      "type": "string"
    }
  },
  "additionalProperties": false
}
